INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('VNIT Nagpur', 'climate', 'Climate > All seasons experienced. Normal climate at Nagpur. Nagpur is known for hot summers and mild winters.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > VNIT has 8 B.Tech branches: CSE (R), ECE (S), EEE (T), Mechanical (U), Civil (W), Chemical+Metallurgy (X), Mining (Y), MME (Z). Each branch is a separate section.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > Class timings: 10 periods per day. Period 1: 8:00-8:55, Period 2: 9:00-9:55, Period 3: 10:00-10:55, Period 4: 11:00-11:55, Period 5: 12:00-12:55. Lunch Break: 1:00-1:55. Period 7: 2:00-2:55, Period 8: 3:00-3:55, Period 9: 4:00-4:55, Period 10: 5:00-5:55.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > Morning periods 1-5 are for lectures (slot codes A-H). Afternoon periods 7-10 are for Practicals and Tutorials. Lunch break is period 6 (1:00-1:55 PM).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > 2nd Semester courses include: M-II (Mathematics-II), PHY (Physics), CP (Computer Programming), CC (Corporate Communication), EC (Electronics), BEE (Basic Electrical Engineering), EG (Engineering Graphics), M-I (Mathematics-I continued), ES (Engineering Sciences), DSPD (Data Structures and Program Design).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > Labs/Practicals: ECC (Electronics), PHY/EE (Physics/Electrical), CADM (Computer Aided Design), BEG/DC/EW (Basic Engineering Graphics/Drawing), CP/PHY (Computer Programming/Physics). Tutorials divided into 4 batches per section.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Nagpur', 'academics', 'Academics > Saturday classes: Refer academic calendar to follow timetable of a specific day (rotating schedule).');
